import { Directive, ElementRef, inject, input } from '@angular/core';

@Directive({
  selector: '[appHighlight]',
  standalone: true,
  host: { '[style.backgroundColor]': 'color()' }
})
export class HighlightDirective {
  color = input('yellow');  // signal input
  private el = inject(ElementRef);

  constructor() {
    effect(() => {
      this.el.nativeElement.style.transition = 'background 0.3s';
    });
  }
}

import { TestBed } from '@angular/core/testing';
import { provideZonelessTesting } from '@angular/core/testing';

describe('CounterComponent', () => {
  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [CounterComponent],
      providers: [provideZonelessTesting()]
    });
  });

  it('increments the count', () => {
    const fixture = TestBed.createComponent(CounterComponent);
    const comp    = fixture.componentInstance;
    comp.increment();
    expect(comp.count()).toBe(1); // signal — just call it!
  });
});

